package kotlinx.datetime.test

import kotlinx.datetime.*
import kotlin.test.*

class BugFixVerificationTest {

    @Test
    fun testLocalDateParseWithManyLeadingZeros() {
        // Test that LocalDate.parse can handle dates with many leading zeros
        val dateString = "+00000000000002022-07-16"
        val date = LocalDate.parse(dateString)
        assertEquals(2022, date.year)
        assertEquals(7, date.monthNumber)
        assertEquals(16, date.dayOfMonth)
    }

    @Test
    fun testLocalDateFormatsISOParseWithManyLeadingZeros() {
        // Test that LocalDate.Formats.ISO.parse can handle dates with many leading zeros
        val dateString = "+00000000000002022-07-16"
        val date = LocalDate.Formats.ISO.parse(dateString)
        assertEquals(2022, date.year)
        assertEquals(7, date.monthNumber)
        assertEquals(16, date.dayOfMonth)
    }

    @Test
    fun testLocalDateTimeParseWithManyLeadingZeros() {
        // Test that LocalDateTime.parse can handle dates with many leading zeros
        val dateTimeString = "+00000000000002022-07-16T10:15:30"
        val dateTime = LocalDateTime.parse(dateTimeString)
        assertEquals(2022, dateTime.year)
        assertEquals(7, dateTime.monthNumber)
        assertEquals(16, dateTime.dayOfMonth)
        assertEquals(10, dateTime.hour)
        assertEquals(15, dateTime.minute)
        assertEquals(30, dateTime.second)
    }

    @Test
    fun testLocalDateTimeFormatsISOParseWithManyLeadingZeros() {
        // Test that LocalDateTime.Formats.ISO.parse can handle dates with many leading zeros
        val dateTimeString = "+00000000000002022-07-16T10:15:30"
        val dateTime = LocalDateTime.Formats.ISO.parse(dateTimeString)
        assertEquals(2022, dateTime.year)
        assertEquals(7, dateTime.monthNumber)
        assertEquals(16, dateTime.dayOfMonth)
        assertEquals(10, dateTime.hour)
        assertEquals(15, dateTime.minute)
        assertEquals(30, dateTime.second)
    }

    @Test
    fun testDateTimePeriodParseRejectsBareP() {
        // Test that DateTimePeriod.parse rejects just "P" without components
        assertFailsWith<DateTimeFormatException> {
            DateTimePeriod.parse("P")
        }
    }

    @Test
    fun testDatePeriodParseRejectsBareP() {
        // Test that DatePeriod.parse rejects just "P" without components
        assertFailsWith<DateTimeFormatException> {
            DatePeriod.parse("P")
        }
    }

    @Test
    fun testDateTimePeriodParseAcceptsValidPeriods() {
        // Verify that valid periods still work
        assertEquals(DateTimePeriod(years = 1, months = 2, days = 3), DateTimePeriod.parse("P1Y2M3D"))
        assertEquals(DateTimePeriod(hours = 1, minutes = 30), DateTimePeriod.parse("PT1H30M"))
        assertEquals(DateTimePeriod(days = 1, hours = 2), DateTimePeriod.parse("P1DT2H"))
    }

    @Test
    fun testDatePeriodParseAcceptsValidPeriods() {
        // Verify that valid date periods still work
        assertEquals(DatePeriod(years = 1, months = 2, days = 3), DatePeriod.parse("P1Y2M3D"))
        assertEquals(DatePeriod(days = 1), DatePeriod.parse("P1D"))
    }
}
"}

