fun main() {
    println("Testing bug fixes...")

    // Test 1: LocalDate with many leading zeros
    try {
        val date = LocalDate.parse("+00000000000002022-07-16")
        println("✓ LocalDate.parse with many leading zeros: $date")
        assert(date.year == 2022 && date.monthNumber == 7 && date.dayOfMonth == 16)
    } catch (e: Exception) {
        println("✗ LocalDate.parse with many leading zeros failed: ${e.message}")
    }

    // Test 2: LocalDate.Formats.ISO with many leading zeros
    try {
        val date = LocalDate.Formats.ISO.parse("+00000000000002022-07-16")
        println("✓ LocalDate.Formats.ISO.parse with many leading zeros: $date")
        assert(date.year == 2022 && date.monthNumber == 7 && date.dayOfMonth == 16)
    } catch (e: Exception) {
        println("✗ LocalDate.Formats.ISO.parse with many leading zeros failed: ${e.message}")
    }

    // Test 3: LocalDateTime with many leading zeros
    try {
        val dateTime = LocalDateTime.parse("+00000000000002022-07-16T10:15:30")
        println("✓ LocalDateTime.parse with many leading zeros: $dateTime")
        assert(dateTime.year == 2022 && dateTime.monthNumber == 7 && dateTime.dayOfMonth == 16)
    } catch (e: Exception) {
        println("✗ LocalDateTime.parse with many leading zeros failed: ${e.message}")
    }

    // Test 4: LocalDateTime.Formats.ISO with many leading zeros
    try {
        val dateTime = LocalDateTime.Formats.ISO.parse("+00000000000002022-07-16T10:15:30")
        println("✓ LocalDateTime.Formats.ISO.parse with many leading zeros: $dateTime")
        assert(dateTime.year == 2022 && dateTime.monthNumber == 7 && dateTime.dayOfMonth == 16)
    } catch (e: Exception) {
        println("✗ LocalDateTime.Formats.ISO.parse with many leading zeros failed: ${e.message}")
    }

    // Test 5: DateTimePeriod.parse rejects bare "P"
    try {
        DateTimePeriod.parse("P")
        println("✗ DateTimePeriod.parse(\"P\") should have thrown an exception")
    } catch (e: DateTimeFormatException) {
        println("✓ DateTimePeriod.parse(\"P\") correctly rejected: ${e.message}")
    }

    // Test 6: DatePeriod.parse rejects bare "P"
    try {
        DatePeriod.parse("P")
        println("✗ DatePeriod.parse(\"P\") should have thrown an exception")
    } catch (e: DateTimeFormatException) {
        println("✓ DatePeriod.parse(\"P\") correctly rejected: ${e.message}")
    }

    // Test 7: Valid periods still work
    try {
        val period = DateTimePeriod.parse("P1Y2M3D")
        println("✓ DateTimePeriod.parse(\"P1Y2M3D\") still works: $period")
    } catch (e: Exception) {
        println("✗ DateTimePeriod.parse(\"P1Y2M3D\") failed: ${e.message}")
    }

    println("\nAll tests completed!")
}
"}

